const mounts = [];
function Row({ id }) { React.useEffect(() => mounts.push(id), []); return <span>{id}</span>; }
const rows = ids => <>{ids.map(id => <Row key={id} id={id} />)}</>;
const view = TestRenderer.create(rows([1, 2]));
view.update(rows([2, 1]));
assert(mounts.join(',') === '1,2');
